        {
          "action": "candidate_edit",
          "title": "为 compressor-1 的出口压力目标提供更高设定占位",
          "target": {
            "type": "unit",
            "id": "compressor-1"
          },
          "rationale": "当前 compressor-1 的入口压力来自 feed-3，为 220 kPa，而现有出口压力目标仅 235 kPa。直接诊断指出该目标与入口压力过近，难以解释所请求的压缩负荷。由于另一条诊断同时说明根因尚未确认，现阶段更适合提出一个局部、非执行式的参数占位建议，而不是进行更大范围的流程改动或假设缺失的下游约束。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.outlet_pressure_target_kpa",
                "current_value": 235,
                "suggested_value_placeholder": "> 235 kPa and meaningfully above 220 kPa inlet",
                "reason": "Increase pressure ratio margin relative to feed pressure so the compressor target is not nearly equal to inlet pressure."
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
